// === NIFTY Writers Zone Detection ===
// ✅ Data source: Option Chain Request1 (NSE option chain format)
// ✅ Structure: data.last_price + data.oc["strike"].ce / .pe

const ocData   = $('Option Chain Request1').first().json?.data || {};
const spotPrice = parseFloat(ocData.last_price) || 0;
const ocMap     = ocData.oc || {};  // { "19600.00": { ce: {...}, pe: {...} }, ... }

// ✅ ATM from Builder node (already computed as nearest 50)
const atmStrike = $('NIFTY Option Chain Builder1').first().json?.atmStrike || Math.round(spotPrice / 50) * 50;

console.log(`✅ Spot: ${spotPrice}, ATM: ${atmStrike}`);
console.log(`✅ Total strikes in OC: ${Object.keys(ocMap).length}`);

// === Parse OC map into flat CE/PE arrays ===
const ceOptions = [];
const peOptions = [];

Object.entries(ocMap).forEach(([strikeStr, optData]) => {
  const strike = parseFloat(strikeStr);
  if (!strike || isNaN(strike)) return;

  // CE
  if (optData.ce) {
    ceOptions.push({
      strike,
      ltp:               parseFloat(optData.ce.last_price)         || 0,
      oi:                parseFloat(optData.ce.oi)                  || 0,
      prevOI:            parseFloat(optData.ce.previous_oi)         || 0,
      iv:                parseFloat(optData.ce.implied_volatility)   || 0,
      avgPrice:          parseFloat(optData.ce.average_price)        || 0,
      delta:             parseFloat(optData.ce.greeks?.delta)        || 0,
      theta:             parseFloat(optData.ce.greeks?.theta)        || 0,
      gamma:             parseFloat(optData.ce.greeks?.gamma)        || 0,
      vega:              parseFloat(optData.ce.greeks?.vega)         || 0,
      distanceFromATM:   Math.abs(strike - atmStrike),
      type: 'CE'
    });
  }

  // PE
  if (optData.pe) {
    peOptions.push({
      strike,
      ltp:               parseFloat(optData.pe.last_price)         || 0,
      oi:                parseFloat(optData.pe.oi)                  || 0,
      prevOI:            parseFloat(optData.pe.previous_oi)         || 0,
      iv:                parseFloat(optData.pe.implied_volatility)   || 0,
      avgPrice:          parseFloat(optData.pe.average_price)        || 0,
      delta:             parseFloat(optData.pe.greeks?.delta)        || 0,
      theta:             parseFloat(optData.pe.greeks?.theta)        || 0,
      gamma:             parseFloat(optData.pe.greeks?.gamma)        || 0,
      vega:              parseFloat(optData.pe.greeks?.vega)         || 0,
      distanceFromATM:   Math.abs(strike - atmStrike),
      type: 'PE'
    });
  }
});

console.log(`📊 CE: ${ceOptions.length}, PE: ${peOptions.length}`);

// Sort by distance from ATM
ceOptions.sort((a, b) => a.distanceFromATM - b.distanceFromATM);
peOptions.sort((a, b) => a.distanceFromATM - b.distanceFromATM);

// === Aggregate stats ===
let maxCELTP = 0, maxPELTP = 0;
let maxCEStrike = 0, maxPEStrike = 0;
let totalCEValue = 0, totalPEValue = 0;
let totalCEOI = 0, totalPEOI = 0;

ceOptions.forEach(o => {
  totalCEValue += o.ltp;
  totalCEOI   += o.oi;
  if (o.ltp > maxCELTP) { maxCELTP = o.ltp; maxCEStrike = o.strike; }
});

peOptions.forEach(o => {
  totalPEValue += o.ltp;
  totalPEOI   += o.oi;
  if (o.ltp > maxPELTP) { maxPELTP = o.ltp; maxPEStrike = o.strike; }
});

const ltpDataAvailable = totalCEValue > 0 || totalPEValue > 0;
const oiDataAvailable  = totalCEOI > 0    || totalPEOI > 0;

// Put-Call ratios
const putCallPremiumRatio = totalCEValue > 0 ? totalPEValue / totalCEValue : 1.0;
const putCallOIRatio      = totalCEOI > 0    ? totalPEOI / totalCEOI       : 1.0;

// === Writers Zone Analysis ===
function analyzeWritersZone() {
  let analysis = {
    zone: 'NEUTRAL', confidence: 0,
    reasoning: [], supportLevels: [], resistanceLevels: [],
    marketStructure: 'BALANCED'
  };

  if (spotPrice === 0) {
    analysis.reasoning.push('⚠️ Spot price missing from Option Chain Request1');
    return analysis;
  }

  if (Object.keys(ocMap).length === 0) {
    analysis.reasoning.push('⚠️ OC data empty — check Option Chain Request1 node');
    return analysis;
  }

  if (!ltpDataAvailable) {
    analysis.reasoning.push('⚠️ All LTPs are 0 — market closed or data feed issue');
  }

  const factor = spotPrice > 20000 ? 100 : 50;

  // 1. Price vs ATM
  const diff = spotPrice - atmStrike;
  if (diff > factor) {
    analysis.zone = 'BULLISH'; analysis.confidence += 0.3;
    analysis.reasoning.push(`Price ${diff.toFixed(0)} pts above ATM ${atmStrike}`);
  } else if (diff < -factor) {
    analysis.zone = 'BEARISH'; analysis.confidence += 0.3;
    analysis.reasoning.push(`Price ${Math.abs(diff).toFixed(0)} pts below ATM ${atmStrike}`);
  } else {
    analysis.reasoning.push(`Price near ATM (diff: ${diff.toFixed(0)} pts)`);
  }

  // 2. Premium PCR
  if (ltpDataAvailable) {
    if (putCallPremiumRatio > 1.15) {
      analysis.marketStructure = 'PUT_PREMIUM_HIGH';
      if (analysis.zone === 'BEARISH') { analysis.confidence += 0.3; analysis.reasoning.push(`PCR ${putCallPremiumRatio.toFixed(2)} confirms BEARISH`); }
      else { analysis.zone = 'BEARISH'; analysis.confidence += 0.2; analysis.reasoning.push(`PCR ${putCallPremiumRatio.toFixed(2)} → BEARISH bias`); }
    } else if (putCallPremiumRatio < 0.85) {
      analysis.marketStructure = 'CALL_PREMIUM_HIGH';
      if (analysis.zone === 'BULLISH') { analysis.confidence += 0.3; analysis.reasoning.push(`PCR ${putCallPremiumRatio.toFixed(2)} confirms BULLISH`); }
      else { analysis.zone = 'BULLISH'; analysis.confidence += 0.2; analysis.reasoning.push(`PCR ${putCallPremiumRatio.toFixed(2)} → BULLISH bias`); }
    } else {
      analysis.reasoning.push(`Balanced PCR: ${putCallPremiumRatio.toFixed(2)}`);
    }
  }

  // 3. OI-based PCR (max pain / writers positioning)
  if (oiDataAvailable) {
    if (putCallOIRatio > 1.3) {
      analysis.confidence += 0.2;
      analysis.reasoning.push(`OI PCR ${putCallOIRatio.toFixed(2)} — heavy PE writing (bullish for market)`);
      if (analysis.zone === 'NEUTRAL') { analysis.zone = 'BULLISH'; }
    } else if (putCallOIRatio < 0.7) {
      analysis.confidence += 0.2;
      analysis.reasoning.push(`OI PCR ${putCallOIRatio.toFixed(2)} — heavy CE writing (bearish for market)`);
      if (analysis.zone === 'NEUTRAL') { analysis.zone = 'BEARISH'; }
    } else {
      analysis.reasoning.push(`OI PCR: ${putCallOIRatio.toFixed(2)} (neutral)`);
    }
  }

  // 4. ATM skew
  const atmCE = ceOptions.find(o => o.strike === atmStrike);
  const atmPE = peOptions.find(o => o.strike === atmStrike);
  if (atmCE && atmPE && atmPE.ltp > 0) {
    const skew = atmCE.ltp / atmPE.ltp;
    if (skew > 1.15) { analysis.confidence += 0.1; analysis.reasoning.push(`ATM skew ${skew.toFixed(2)} → CE costlier (bullish)`); }
    else if (skew < 0.85) { analysis.confidence += 0.1; analysis.reasoning.push(`ATM skew ${skew.toFixed(2)} → PE costlier (bearish)`); }
  }

  // 5. Support = highest OI PE strikes below spot
  //    Resistance = highest OI CE strikes above spot
  analysis.supportLevels = peOptions
    .filter(o => o.strike <= spotPrice && (o.oi > 0 || o.ltp > 0))
    .sort((a, b) => b.oi - a.oi)
    .slice(0, 3).map(o => o.strike);

  analysis.resistanceLevels = ceOptions
    .filter(o => o.strike >= spotPrice && (o.oi > 0 || o.ltp > 0))
    .sort((a, b) => b.oi - a.oi)
    .slice(0, 3).map(o => o.strike);

  analysis.confidence = Math.min(analysis.confidence, 1.0);

  if (analysis.confidence < 0.2) {
    analysis.zone = 'NEUTRAL';
    analysis.reasoning.push('Insufficient conviction for directional bias');
  }

  return analysis;
}

const writersAnalysis = analyzeWritersZone();

return {
  writersZone:          writersAnalysis.zone,
  confidence:           Math.round(writersAnalysis.confidence * 100) / 100,
  maxCELTP, maxPELTP, maxCEStrike, maxPEStrike,
  totalCEValue:         Math.round(totalCEValue * 100) / 100,
  totalPEValue:         Math.round(totalPEValue * 100) / 100,
  totalCEOI,
  totalPEOI,
  putCallPremiumRatio:  Math.round(putCallPremiumRatio * 100) / 100,
  putCallOIRatio:       Math.round(putCallOIRatio * 100) / 100,
  ltpDataAvailable,
  oiDataAvailable,
  supportLevels:        writersAnalysis.supportLevels,
  resistanceLevels:     writersAnalysis.resistanceLevels,
  reasoning:            writersAnalysis.reasoning,
  marketStructure:      writersAnalysis.marketStructure,
  currentPrice:         spotPrice,
  atmStrike,
  distanceFromATM:      Math.abs(spotPrice - atmStrike),
  underlying:           'NIFTY',
  ceOptionsCount:       ceOptions.length,
  peOptionsCount:       peOptions.length,
  timestamp:            new Date().toISOString()
};

// ============================================================
// NIFTY SIGNAL ENGINE v2.1 — STREAK BUG FIXED
// Fix: replaced global (resets every run) with $getWorkflowStaticData
//      which actually persists between n8n workflow executions
// ============================================================

// === INPUTS ===
let tech = {};
let writers = {};

try {
    tech = $node["Calculate All Technical Indicators1"].json;
} catch (e) {
    return [{ json: { finalSignal: "ERROR", reason: "Node 'Calculate All Technical Indicators1' missing.", regime: "DATA_FAILURE" } }];
}

try {
    writers = $node["Writers Zone Analysis1"].json;
} catch (e) {
    writers = { writersZone: "NEUTRAL", confidence: 0 };
}

// === TUNABLE THRESHOLDS ===
const CONFIG = {
    BUY_CE_MIN_CONFIDENCE: 0,
    BUY_PE_MIN_CONFIDENCE: -0,
    ADX_TREND_THRESHOLD: 20,
    RSI_OVERSOLD: 35,
    RSI_OVERBOUGHT: 65,
    WRITERS_WEIGHT: 20,
    REPEAT_PROTECTION: true,
    MIN_STREAK: 1,          // ✅ Set to 1 for live trading (streak=2 only for backtest)
    PAPER_TRADING: false,
};

// ✅ FIX: Use n8n static data — persists across workflow executions (unlike global)
const mem = $getWorkflowStaticData('global');

// Initialize memory fields if first run
if (!mem.lastSignal) mem.lastSignal = "";
if (!mem.prevMACDHist) mem.prevMACDHist = 0;
if (!mem.streakSignal) mem.streakSignal = "";
if (!mem.streakCount) mem.streakCount = 0;
if (!mem.lastFireTime) mem.lastFireTime = null;

// === READ ALL INDICATORS ===
const adxValue = parseFloat(tech.ADX?.value) || 0;
const rsiValue = parseFloat(tech.RSI?.rsi) || 50;
const vixValue = parseFloat(tech.VIX?.vix) || 15;
const macdHist = parseFloat(tech.MACD?.histogram) || 0;
const macdValue = parseFloat(tech.MACD?.macd) || 0;
const macdSignal = parseFloat(tech.MACD?.signal) || 0;
const ema20Status = tech.EMA20?.status || "Neutral";
const sma50Status = tech.SMA50?.status || "Neutral";
const stochStatus = tech.Stochastic?.status || "Neutral";
const vwapStatus = tech.VWAP?.status || "Below";
const superTrend = tech.SuperTrend?.status || "Neutral";
const aroonStatus = tech.Aroon?.status || "Neutral";
const psarStatus = tech.ParabolicSAR?.status || "Neutral";
const cciStatus = tech.CCI?.status || "Neutral";
const mfiStatus = tech.MFI?.status || "Neutral";
const priceAction = tech.PriceAction?.type || "Ranging";
const volStrength = tech.VolumeStrength?.type || "Weak Volume";
const bbStatus = tech.BollingerBands?.status || "Within Bands";
const ltp = parseFloat(tech.LTP) || 0;
const candlePatterns = Array.isArray(tech.CandlePatterns) ? tech.CandlePatterns : [];

// === SAFETY GATES ===
if (ltp <= 0) {
    return [{ json: { finalSignal: "ERROR", reason: "LTP is 0 or missing.", regime: "DATA_FAILURE" } }];
}

// Market hours gate (IST 09:15–15:30)
const now = new Date();
const istTime = new Date(now.toLocaleString("en-US", { timeZone: "Asia/Kolkata" }));
const timeAsInt = istTime.getHours() * 100 + istTime.getMinutes();
const isInsideMarketHours = (timeAsInt >= 915 && timeAsInt <= 1530);

if (!isInsideMarketHours && !CONFIG.PAPER_TRADING) {
    return [{ json: { finalSignal: "MARKET_CLOSED", reason: `Outside hours: ${timeAsInt}`, regime: "OFF_MARKET" } }];
}

// VIX hard stop
if (vixValue >= 18) {
    mem.lastSignal = "AVOID";
    return [{ json: { finalSignal: "AVOID", confidence: 0, reason: `VIX too high: ${vixValue}`, regime: "HIGH_VOLATILITY", LTP: ltp } }];
}

// ADX + Price Action filter
const isTrending = adxValue >= CONFIG.ADX_TREND_THRESHOLD;
const isRanging = priceAction === "Ranging";

if (!isTrending && isRanging) {
    mem.lastSignal = "SIDEWAYS";
    return [{ json: { finalSignal: "SIDEWAYS", confidence: 0, reason: `ADX=${adxValue.toFixed(1)} & Ranging`, regime: "SIDEWAYS_RANGING", LTP: ltp } }];
}

// === SCORING ===
let score = 0;
let reasons = [];
let indicatorsUsed = {};

const add = (val, weight, label, key) => {
    if (val) {
        score += weight;
        reasons.push(label);
        indicatorsUsed[key] = (indicatorsUsed[key] || 0) + weight;
    }
};

// MACD Histogram direction
const macdHistFlippedBullish = mem.prevMACDHist < 0 && macdHist > 0;
const macdHistFlippedBearish = mem.prevMACDHist > 0 && macdHist < 0;
const macdHistGrowingBullish = macdHist > 0 && macdHist > mem.prevMACDHist;
const macdHistGrowingBearish = macdHist < 0 && macdHist < mem.prevMACDHist;
const macdAboveZero = macdValue > macdSignal;
const macdBelowZero = macdValue < macdSignal;

add(macdHistFlippedBullish, 20, "MACD Histogram Bullish Flip", "MACD");
add(macdHistFlippedBearish, -20, "MACD Histogram Bearish Flip", "MACD");
add(macdHistGrowingBullish && !macdHistFlippedBullish, 10, "MACD Histogram Rising", "MACD");
add(macdHistGrowingBearish && !macdHistFlippedBearish, -10, "MACD Histogram Falling", "MACD");
add(macdAboveZero && !macdHistFlippedBullish && !macdHistGrowingBullish, 5, "MACD Bullish Crossover", "MACD");
add(macdBelowZero && !macdHistFlippedBearish && !macdHistGrowingBearish, -5, "MACD Bearish Crossover", "MACD");

// RSI
add(rsiValue < CONFIG.RSI_OVERSOLD, 15, `RSI Oversold (${rsiValue.toFixed(1)})`, "RSI");
add(rsiValue > CONFIG.RSI_OVERBOUGHT, -15, `RSI Overbought (${rsiValue.toFixed(1)})`, "RSI");
add(rsiValue >= 45 && rsiValue < CONFIG.RSI_OVERBOUGHT && rsiValue >= CONFIG.RSI_OVERSOLD, 5, `RSI Neutral-Bullish (${rsiValue.toFixed(1)})`, "RSI");
add(rsiValue <= 55 && rsiValue > CONFIG.RSI_OVERSOLD && rsiValue <= CONFIG.RSI_OVERBOUGHT, -5, `RSI Neutral-Bearish (${rsiValue.toFixed(1)})`, "RSI");

// EMA + SMA
const emaBullish = ema20Status === "Bullish", emaBearish = ema20Status === "Bearish";
const smaBullish = sma50Status === "Bullish", smaBearish = sma50Status === "Bearish";
add(emaBullish, 10, "EMA20 Bullish", "EMA");
add(emaBearish, -10, "EMA20 Bearish", "EMA");
add(smaBullish, 5, "SMA50 Bullish", "SMA");
add(smaBearish, -5, "SMA50 Bearish", "SMA");
add(emaBullish && smaBullish, 10, "EMA+SMA Both Bullish", "EMA_SMA");
add(emaBearish && smaBearish, -10, "EMA+SMA Both Bearish", "EMA_SMA");

// SuperTrend + PSAR
add(superTrend === "Bullish", 15, "SuperTrend Buy", "SuperTrend");
add(superTrend === "Bearish", -15, "SuperTrend Sell", "SuperTrend");
add(psarStatus === "Bullish", 8, "PSAR Bullish", "PSAR");
add(psarStatus === "Bearish", -8, "PSAR Bearish", "PSAR");

// VWAP, Aroon, Stoch, CCI, MFI
add(vwapStatus === "Above", 8, "Above VWAP", "VWAP");
add(vwapStatus === "Below", -8, "Below VWAP", "VWAP");
add(aroonStatus === "Uptrend", 8, "Aroon Uptrend", "Aroon");
add(aroonStatus === "Downtrend", -8, "Aroon Downtrend", "Aroon");
add(stochStatus === "Oversold", 8, "Stoch Oversold", "Stoch");
add(stochStatus === "Overbought", -8, "Stoch Overbought", "Stoch");
add(cciStatus === "Buy", 5, "CCI Buy", "CCI");
add(cciStatus === "Sell", -5, "CCI Sell", "CCI");
add(mfiStatus === "Oversold", 5, "MFI Oversold", "MFI");
add(mfiStatus === "Overbought", -5, "MFI Overbought", "MFI");

// Bollinger Bands
add(bbStatus === "Breakout Up", 10, "BB Breakout Up", "BB");
add(bbStatus === "Breakout Down", -10, "BB Breakout Down", "BB");
if (bbStatus === "Within Bands") {
    add(emaBullish, 3, "BB Normal (trending up)", "BB");
    add(emaBearish, -3, "BB Normal (trending down)", "BB");
}

// Volume
const volStrong = volStrength.includes("Confirmed") || volStrength === "Normal OBV";
if (volStrong && score > 0) add(true, 5, "Volume Confirms Bullish", "Volume");
if (volStrong && score < 0) add(true, -5, "Volume Confirms Bearish", "Volume");
if (volStrength === "Weak Volume") {
    if (score > 0) score -= 5;
    if (score < 0) score += 5;
    reasons.push("Weak Volume (penalised)");
}

// Candle alignment
const BULLISH_CANDLES = ["Hammer", "Morning Star", "Bullish Engulfing", "Bullish Marubozu", "Inverted Hammer"];
const BEARISH_CANDLES = ["Shooting Star", "Evening Star", "Bearish Engulfing", "Bearish Marubozu", "Hanging Man"];
let candleBoost = 0;
candlePatterns.forEach(pattern => {
    if (BULLISH_CANDLES.includes(pattern) && score > 0) { candleBoost += 8; reasons.push(`Bullish Candle: ${pattern}`); }
    else if (BEARISH_CANDLES.includes(pattern) && score < 0) { candleBoost -= 8; reasons.push(`Bearish Candle: ${pattern}`); }
});
score += candleBoost;
if (candleBoost !== 0) indicatorsUsed["Candle"] = candleBoost;

// Writers Zone
const wZone = writers?.writersZone || "NEUTRAL";
const wConf = parseFloat(writers?.confidence) || 0;
const wPCR = parseFloat(writers?.putCallPremiumRatio) || 1.0;
const hasRealPCR = wPCR !== 1.0;
if (hasRealPCR && wZone !== "NEUTRAL" && wConf >= 0.2) {
    const wWeight = CONFIG.WRITERS_WEIGHT * wConf;
    if (wZone === "BULLISH") add(true, wWeight, `Writers BULLISH (PCR:${wPCR})`, "Writers");
    else if (wZone === "BEARISH") add(true, -wWeight, `Writers BEARISH (PCR:${wPCR})`, "Writers");
} else {
    let status = !hasRealPCR ? "No Data" : (wZone === "NEUTRAL" ? "Neutral" : "Low Confidence");
    reasons.push(`Writers: ${status} (PCR:${wPCR.toFixed(2)}, Conf:${wConf})`);
}

// ADX bonus
if (adxValue >= 25) {
    if (score > 0) { score += 8; reasons.push(`Strong ADX=${adxValue.toFixed(1)} (boost)`); }
    if (score < 0) { score -= 8; reasons.push(`Strong ADX=${adxValue.toFixed(1)} (boost)`); }
}
if (adxValue >= 15 && adxValue < CONFIG.ADX_TREND_THRESHOLD) {
    score = score * 0.8;
    reasons.push(`Weak ADX=${adxValue.toFixed(1)} → reduced 20%`);
}

// === STREAK CONFIRMATION ===
let currentRawSignal = "WAIT";
if (score >= CONFIG.BUY_CE_MIN_CONFIDENCE) currentRawSignal = "BUY CALL (CE)";
else if (score <= CONFIG.BUY_PE_MIN_CONFIDENCE) currentRawSignal = "BUY PUT (PE)";

if (currentRawSignal === mem.streakSignal && currentRawSignal !== "WAIT") {
    mem.streakCount = mem.streakCount + 1;
} else {
    mem.streakSignal = currentRawSignal;
    mem.streakCount = currentRawSignal === "WAIT" ? 0 : 1;
}

const streakConfirmed = mem.streakCount >= CONFIG.MIN_STREAK;

// === FINAL DECISION ===
let finalSignal = "WAIT";
let blockedReason = "";

if (currentRawSignal === "WAIT") {
    blockedReason = `Score ${score.toFixed(1)} between thresholds (${CONFIG.BUY_PE_MIN_CONFIDENCE} to ${CONFIG.BUY_CE_MIN_CONFIDENCE})`;
} else if (!streakConfirmed) {
    blockedReason = `Streak: ${mem.streakCount}/${CONFIG.MIN_STREAK} bars (building ${currentRawSignal})`;
} else if (CONFIG.REPEAT_PROTECTION && currentRawSignal === mem.lastSignal) {
    blockedReason = `Repeat protection: already fired ${mem.lastSignal}`;
} else {
    finalSignal = currentRawSignal;
}

// ✅ Save back to static data (persists to next execution)
mem.lastSignal = finalSignal !== "WAIT" ? finalSignal : mem.lastSignal;
mem.prevMACDHist = macdHist;
mem.lastFireTime = finalSignal !== "WAIT" ? new Date().toISOString() : mem.lastFireTime;

// === REGIME ===
let regime = "MIXED";
if (vixValue >= 18) regime = "HIGH_VOLATILITY";
else if (!isTrending && isRanging) regime = "SIDEWAYS_RANGING";
else if (!isTrending) regime = "SIDEWAYS_WEAK_TREND";
else if (superTrend === "Bullish" && emaBullish) regime = "STRONG_BULLISH";
else if (superTrend === "Bearish" && emaBearish) regime = "STRONG_BEARISH";
else if (emaBullish) regime = "BULLISH_TREND";
else if (emaBearish) regime = "BEARISH_TREND";

// === OUTPUT ===
return [{
    json: {
        finalSignal,
        rawSignal: currentRawSignal,
        confidence: Math.round(score * 100) / 100,
        streakCount: mem.streakCount,
        streakNeeded: CONFIG.MIN_STREAK,
        streakConfirmed,
        reason: reasons.join(" | "),
        blockedReason: blockedReason || null,
        indicators: indicatorsUsed,
        regime,
        LTP: ltp,
        VIX: vixValue,
        ADX: adxValue,
        RSI: rsiValue,
        MACDHist: macdHist,
        MACDFlip: macdHistFlippedBullish ? "BULLISH_FLIP" : macdHistFlippedBearish ? "BEARISH_FLIP" : "NONE",
        SuperTrend: superTrend,
        EMA20: ema20Status,
        VWAP: vwapStatus,
        writersZone: wZone,
        writersConfidence: wConf,
        putCallRatio: wPCR,
        writersUsed: hasRealPCR && wZone !== "NEUTRAL" && wConf >= 0.2,
        supportLevels: writers?.supportLevels || [],
        resistanceLevels: writers?.resistanceLevels || [],
        lastSignal: mem.lastSignal,
        lastFireTime: mem.lastFireTime
    }
}];
